# Round decimal numbers (including 0.0000, 278.8571, etc.) to 2 d.p.
# Leaves integers without decimals unchanged, and preserves text like Task 1.
def round_decimals_to_2dp(match):
    s = match.group(0)
    try:
        return f"{float(s):.2f}"
    except ValueError:
        return s

# Match signed/unsigned decimals with at least 1 digit after decimal point
rounded = re.sub(r'(?<![\w])[-+]?\d+\.\d+(?![\w])', round_decimals_to_2dp, latex_text)

print(rounded)